import mergeOptions from '@dubaua/merge-options';
import Observable from '@dubaua/observable';
import calculateActiveIndex from './utils/calculate-active-index';
import calculateLayerProgress from './utils/calculate-layer-progress';
import calculateLayerStateArray from './utils/calculate-layer-state-array';
import calculateLayerTransform from './utils/calculate-layer-transform';
import calculateScrollTarget from './utils/calculate-scroll-target';
import { EventNames } from './events';
import { CroppedFullAbsoluteStyles, InteractiveStyles, NotInteractiveStyles } from './utils/styles';
import { ImmerserSelectors } from './utils/selectors';
import { InitialDebug, OptionConfig } from './options';
import { getOriginalHandler, wrapOnceHandler } from './utils/once-handler';
import assignInlineStyles from './utils/assign-inline-styles';
import getLastScrollPosition from './utils/get-last-scroll-position';
import queryElementArray from './utils/query-element-array';
import validateLayerStateInput from './utils/validate-layer-state-input';
import type { ICalculationSnapshot, ILayerCalculation, ILayoutMetrics } from './internal-types';
import type {
  ActiveLayerChangeHandler,
  BaseHandler,
  EventHandlers,
  EventName,
  HandlerArgs,
  HandlerByEventName,
  LayersUpdateHandler,
  Options,
  RuntimeOptions,
  SolidClassnames,
  SolidClassnamesByLayerId,
} from './types';

const MessagePrefix = '[immerser]:';
const RuntimeOptionNames: (keyof RuntimeOptions)[] = [
  'debug',
  'fromViewportWidth',
  'hasToUpdateHash',
  'isScrollHandled',
  'pagerThreshold',
  'scrollAdjustDelay',
  'scrollAdjustThreshold',
];

interface IReportParams {
  docsHash?: string;
  error?: unknown;
  isWarning?: boolean;
  message: string;
}

interface IDomLayerState {
  id: string;
  layerNode: HTMLElement;
  maskInnerNode: HTMLElement | null;
  maskNode: HTMLElement | null;
  order: number;
  solidClassnames: SolidClassnames | null;
}

interface ISnapshotTransition {
  previousActiveIndex: number;
  snapshot: ICalculationSnapshot;
}

interface IMaskMarkup {
  createdMask: boolean;
  maskInnerNode: HTMLElement;
  maskNode: HTMLElement;
}

interface IClonedSolid {
  maskInnerNode: HTMLElement;
  node: HTMLElement;
}

interface IPreparedLayerMarkup extends IMaskMarkup {
  clonedSolidArray: IClonedSolid[];
  solidNodeArray: HTMLElement[];
}

/** @public Main Immerser controller orchestrating markup cloning and scroll-driven transitions. */
export default class Immerser {
  private _options!: Options;
  private _selectors = ImmerserSelectors;
  private _userOptions: Partial<Options> = {};
  private _layerStateById = new Map<string, IDomLayerState>();
  private _isMounted = false;
  private _isBound = false;
  private _rootNode: HTMLElement | null = null;
  private _layerNodeArray: HTMLElement[] = [];
  private _pagerLinkNodeArray: HTMLElement[] = [];
  private _synchroHoverNodeArray: HTMLElement[] = [];
  private _resizeFrameId: number | null = null;
  private _resizeObserver: ResizeObserver | null = null;
  private _scrollFrameId: number | null = null;
  private _scrollAdjustTimerId: ReturnType<typeof setTimeout> | null = null;
  private _reactiveWindowWidth = new Observable<number>(-1);
  private _reactiveSynchroHoverId = new Observable<string | null>(null);
  private _unsubscribeSynchroHover: (() => void) | null = null;
  private _unsubscribeToggleBindOnResize: (() => void) | null = null;
  private _handlers: Record<EventName, Set<HandlerByEventName[EventName]>> = {
    init: new Set(),
    bind: new Set(),
    unbind: new Set(),
    destroy: new Set(),
    activeLayerChange: new Set(),
    layersUpdate: new Set(),
  };
  private _onResize: (() => void) | null = null;
  private _onScroll: (() => void) | null = null;
  private _onSynchroHoverMouseOver: ((e: MouseEvent) => void) | null = null;
  private _onSynchroHoverMouseOut: (() => void) | null = null;
  private _originalSolidNodeArray: HTMLElement[] = [];
  private _preparedLayerMarkupById = new Map<string, IPreparedLayerMarkup>();
  private _layerCalculationArray: ILayerCalculation[] = [];
  private _layout: ILayoutMetrics | null = null;
  private _snapshot: ICalculationSnapshot = {
    activeIndex: -1,
    layerProgressArray: [],
    transforms: [],
  };

  /** Enables warnings/errors reporting. Defaults to NODE_ENV===development. */
  public debug = InitialDebug;

  /**
   * Creates immerser instance and runs DOM setup unless autoMount is disabled.
   * @param userOptions - overrides for defaults defined in OptionConfig if pass validation
   */
  constructor(userOptions?: Partial<Options>) {
    this._init(userOptions);
  }

  private _init(userOptions?: Partial<Options>): void {
    this._userOptions = userOptions ?? {};
    const options = this._mergeOptions(this._userOptions);
    this._options = options;
    this.debug = options.debug;
    this._registerHandlersFromOptions(options);

    if (options.autoMount) {
      this.mount();
    }
    this._emit('init', this);
  }

  /** Merges user options with defaults and attaches helper metadata to messages. */
  private _mergeOptions(userOptions?: Partial<Options>): Options {
    return mergeOptions({
      optionConfig: OptionConfig,
      userOptions,
      prefix: MessagePrefix,
      suffix: '\nCheck out documentation https://github.com/dubaua/immerser#options',
      strict: false,
    });
  }

  /** Saves event handlers passed via options into internal registry. */
  private _registerHandlersFromOptions(options: Options): void {
    if (!options.on) {
      return;
    }
    EventNames.forEach((eventName) => {
      const handler = options.on?.[eventName];
      if (typeof handler === 'function') {
        this.on(eventName, handler);
      }
    });
  }

  /** Executes registered event handlers with provided arguments. */
  private _emit<K extends EventName>(eventName: K, ...args: HandlerArgs<K>): void {
    const handlerSet = this._handlers[eventName];
    handlerSet.forEach((handler: HandlerByEventName[K]) => {
      try {
        handler.apply(undefined, args);
      } catch (error) {
        this._report({
          message: `handler for ${eventName} event failed`,
          error,
          docsHash: '#events',
        });
      }
    });
  }

  private _report({ message, error, isWarning = false, docsHash = '' }: IReportParams): void {
    const resultMessage = `${MessagePrefix} ${message} \nCheck out documentation https://github.com/dubaua/immerser${docsHash}`;

    if (isWarning) {
      if (!this.debug) {
        return;
      }

      error !== undefined ? console.warn(resultMessage, error) : console.warn(resultMessage);

      return;
    }

    throw new Error(resultMessage, { cause: error });
  }

  /** Returns layer states in DOM order for the array-based calculation boundary. */
  private get _orderedLayerStateArray(): IDomLayerState[] {
    return Array.from(this._layerStateById.values()).sort((a, b) => a.order - b.order);
  }

  /** Collects root, layer and solid nodes from DOM. */
  private _setDomNodes(selectorRoot: ParentNode): void {
    this._rootNode = selectorRoot.querySelector<HTMLElement>(this._selectors.root);
    this._layerNodeArray = queryElementArray({ selector: this._selectors.layer, parent: selectorRoot });
  }

  /** Validates required markup presence and reports descriptive errors. */
  private _validateMarkup(): void {
    if (!this._rootNode) {
      this._report({
        message: 'root node not found.',
        docsHash: '#prepare-your-markup',
      });
    }
    if (this._layerNodeArray.length === 0) {
      this._report({
        message: 'layer nodes not found.',
        docsHash: '#prepare-your-markup',
      });
    }
  }

  /** Reads per-layer classname configs from data attributes if provided. */
  private _readClassnamesFromMarkup(): void {
    this._layerNodeArray.forEach((layerNode) => {
      if (layerNode.dataset.immerserLayerConfig) {
        try {
          this._options.solidClassnamesByLayerId[layerNode.id] = JSON.parse(layerNode.dataset.immerserLayerConfig);
        } catch (error) {
          this._report({
            message: 'Failed to parse JSON classname configuration.',
            error,
            docsHash: '#options',
          });
        }
      }
    });
  }

  /** Ensures every layer has the explicit unique id required by the public contract. */
  private _validateLayerIds(): void {
    const layerIdSet = new Set<string>();
    this._layerNodeArray.forEach((layerNode, layerIndex) => {
      const { id } = layerNode;
      if (!id) {
        this._report({
          message: `layer id not found for layer at index ${layerIndex}.`,
          docsHash: '#prepare-your-markup',
        });
      }
      if (layerIdSet.has(id)) {
        this._report({
          message: `duplicate layer id "${id}".`,
          docsHash: '#prepare-your-markup',
        });
      }
      layerIdSet.add(id);
    });
  }

  /** Ensures classname configuration references only existing layer ids. */
  private _validateSolidClassnamesConfig(): void {
    const solidClassnamesByLayerId = this._options.solidClassnamesByLayerId;
    if (
      !solidClassnamesByLayerId ||
      typeof solidClassnamesByLayerId !== 'object' ||
      Array.isArray(solidClassnamesByLayerId)
    ) {
      this._report({
        message: 'solidClassnamesByLayerId must be an object',
        docsHash: '#options',
      });
      return;
    }

    const entries = Object.entries(solidClassnamesByLayerId);
    const hasInvalidEntry = entries.some(
      (entry) =>
        !entry[1] ||
        typeof entry[1] !== 'object' ||
        Array.isArray(entry[1]) ||
        Object.values(entry[1]).some((classname) => typeof classname !== 'string'),
    );
    if (hasInvalidEntry) {
      this._report({
        message: 'solidClassnamesByLayerId entries must map solid ids to classname strings',
        docsHash: '#options',
      });
      return;
    }

    const layerIdArray = this._layerNodeArray.map(({ id }) => id);
    const unknownLayerId = entries.map(([layerId]) => layerId).find((layerId) => !layerIdArray.includes(layerId));
    if (unknownLayerId) {
      this._report({
        message: `solidClassnamesByLayerId contains unknown layer id "${unknownLayerId}"`,
        docsHash: '#options',
      });
    }
  }

  /** Creates initial LayerState entries for every layer. */
  private _initLayerStateMap(): void {
    this._layerNodeArray.forEach((layerNode, order) => {
      this._addLayerState(layerNode.id, layerNode, order, this._options.solidClassnamesByLayerId[layerNode.id] ?? null);
    });
  }

  /** Adds one validated layer state to the registry. */
  private _addLayerState(
    id: string,
    layerNode: HTMLElement,
    order: number,
    solidClassnames: SolidClassnames | null = null,
  ): IDomLayerState {
    this._validateLayerStateInput(id, layerNode, order, solidClassnames);
    const layerState: IDomLayerState = {
      id,
      layerNode,
      maskInnerNode: null,
      maskNode: null,
      order,
      solidClassnames,
    };
    layerNode.id = id;
    this._layerStateById.set(id, layerState);
    return layerState;
  }

  /** Ensures dynamic layer input does not break id/order based runtime addressing. */
  private _validateLayerStateInput(
    id: string,
    layerNode: HTMLElement,
    order: number,
    solidClassnames: SolidClassnames | null,
  ): void {
    const validationMessage = validateLayerStateInput({
      existingLayerIdArray: Array.from(this._layerStateById.keys()),
      existingLayerOrderArray: this._orderedLayerStateArray.map(({ order: existingOrder }) => existingOrder),
      id,
      layerNode,
      order,
      solidClassnames,
    });

    if (validationMessage) {
      this._report({
        message: validationMessage,
        docsHash: '#prepare-your-markup',
      });
    }
  }

  /** Subscribes to window width changes to enable/disable runtime based on breakpoint. */
  private _toggleBindOnResizeObserver(): void {
    this._unsubscribeToggleBindOnResize = this._reactiveWindowWidth.subscribe((nextWindowWidth) => {
      if (nextWindowWidth >= this._options.fromViewportWidth) {
        if (!this._isBound) {
          this.enable();
        }
      } else if (this._isBound) {
        this.disable();
      }
    });
  }

  /** Recalculates sizes and thresholds for each layer and updates window width observable. */
  private _setSizes(): void {
    const layout = {
      layers: this._orderedLayerStateArray.map(({ layerNode }) => ({
        bottom: layerNode.offsetTop + layerNode.offsetHeight,
        top: layerNode.offsetTop,
      })),
      rootHeight: (this._rootNode as HTMLElement).offsetHeight,
      rootTop: (this._rootNode as HTMLElement).offsetTop,
      viewportHeight: window.innerHeight,
    };
    this._layout = layout;
    this._layerCalculationArray = calculateLayerStateArray(layout);
    if (this._snapshot.layerProgressArray.length === 0) {
      this._snapshot = {
        ...this._snapshot,
        layerProgressArray: layout.layers.map(() => 0),
      };
    }

    this._reactiveWindowWidth.value = window.innerWidth;
  }

  /** Attaches scroll and resize listeners respecting isScrollHandled flag. */
  private _addScrollAndResizeListeners(): void {
    if (this._options.isScrollHandled) {
      this._addScrollListener();
    }
    this._onResize = this._handleResize.bind(this);
    window.addEventListener('resize', this._onResize, false);
    window.addEventListener('orientationchange', this._onResize, false);
    if (typeof ResizeObserver !== 'undefined') {
      this._resizeObserver = new ResizeObserver(this._onResize);
      this._resizeObserver.observe(this._rootNode);
    }
  }

  /** Attaches the scroll listener once when scroll handling is enabled. */
  private _addScrollListener(): void {
    if (this._onScroll) {
      return;
    }
    this._onScroll = this._handleScroll.bind(this);
    window.addEventListener('scroll', this._onScroll, false);
  }

  /** Clears internal caches, observables and references after destroy. */
  private _resetInternalState(): void {
    this._layerStateById.clear();
    this._isMounted = false;
    this._isBound = false;
    this._rootNode = null;
    this._layerNodeArray = [];
    this._pagerLinkNodeArray = [];
    this._synchroHoverNodeArray = [];
    this._resizeFrameId = null;
    this._resizeObserver = null;
    this._scrollFrameId = null;
    this._scrollAdjustTimerId = null;
    this._reactiveWindowWidth.reset();
    this._reactiveSynchroHoverId.reset();
    this._unsubscribeSynchroHover = null;
    this._unsubscribeToggleBindOnResize = null;
    this._onResize = null;
    this._onScroll = null;
    this._onSynchroHoverMouseOver = null;
    this._onSynchroHoverMouseOut = null;
    this._originalSolidNodeArray = [];
    this._preparedLayerMarkupById.clear();
    this._reset();
  }

  /** Prepares markup from the current DOM structure. */
  private _prepareMarkup(): void {
    this._orderedLayerStateArray.forEach((layerState) => {
      this._setLayerState(this.prepareLayer(layerState));
    });
    this._syncCreatedMasksAria();
  }

  /** Restores markup according to controller-recorded ownership. */
  private _cleanupMarkup(): void {
    this.cleanup();
    this._orderedLayerStateArray.forEach((layerState) => {
      this._setLayerState({ ...layerState, maskInnerNode: null, maskNode: null });
    });
  }

  /** Writes an updated layer state into the id registry. */
  private _setLayerState(layerState: IDomLayerState): void {
    this._layerStateById.set(layerState.id, layerState);
  }

  /** Applies created mask aria-hidden according to current layer order. */
  private _syncCreatedMasksAria(): void {
    this.syncCreatedMasksAria(this._orderedLayerStateArray.map(({ id }) => id));
  }

  /** Collects pager links that will receive runtime active state. */
  private _initPagerLinks(): void {
    this._pagerLinkNodeArray = queryElementArray({ selector: this._selectors.pagerLink, parent: this._rootNode });
  }

  /** Sets up synchro hover listeners and reactive updates. */
  private _initHoverSynchro(): void {
    this._synchroHoverNodeArray = queryElementArray({ selector: this._selectors.synchroHover, parent: this._rootNode });

    this._onSynchroHoverMouseOver = (e: MouseEvent): void => {
      const target = e.currentTarget as HTMLElement;
      const synchroHoverId = target.dataset.immerserSynchroHover;
      this._reactiveSynchroHoverId.value = synchroHoverId;
    };

    this._onSynchroHoverMouseOut = (): void => {
      this._reactiveSynchroHoverId.value = null;
    };

    this._synchroHoverNodeArray.forEach((synchroHoverNode) => {
      synchroHoverNode.addEventListener('mouseover', this._onSynchroHoverMouseOver!);
      synchroHoverNode.addEventListener('mouseout', this._onSynchroHoverMouseOut!);
    });
  }

  /** Subscribes to synchronized hover updates. */
  private _attachCallbacks(): void {
    if (this._synchroHoverNodeArray.length > 0) {
      this._unsubscribeSynchroHover = this._reactiveSynchroHoverId.subscribe(this._drawSynchroHover.bind(this));
    }
  }

  /** Unsubscribes from synchronized hover updates. */
  private _detachCallbacks(): void {
    this._unsubscribeSynchroHover?.();
  }

  /** Removes hover listeners from synchro hover nodes. */
  private _removeSyncroHoverListeners(): void {
    this._synchroHoverNodeArray.forEach((synchroHoverNode) => {
      synchroHoverNode.removeEventListener('mouseover', this._onSynchroHoverMouseOver!);
      synchroHoverNode.removeEventListener('mouseout', this._onSynchroHoverMouseOut!);
    });
  }

  /** Clears runtime active state from pager links. */
  private _clearPagerLinks(): void {
    this._pagerLinkNodeArray.forEach((node) => {
      node.classList.remove(this._options.pagerLinkActiveClassname);
    });
  }

  /** Removes browser listeners that outlive individual runtime cycles. */
  private _removeScrollAndResizeListeners(): void {
    this._removeScrollListener();
    if (this._onResize) {
      window.removeEventListener('resize', this._onResize, false);
      window.removeEventListener('orientationchange', this._onResize, false);
    }
    this._resizeObserver?.disconnect();
  }

  /** Removes the scroll listener if it is attached. */
  private _removeScrollListener(): void {
    if (!this._onScroll) {
      return;
    }
    window.removeEventListener('scroll', this._onScroll, false);
    this._onScroll = null;
  }

  /** Cancels the pending scroll animation frame. */
  private _cancelScrollFrame(): void {
    if (this._scrollFrameId !== null) {
      window.cancelAnimationFrame(this._scrollFrameId);
      this._scrollFrameId = null;
    }
  }

  /** Cancels the pending resize animation frame. */
  private _cancelResizeFrame(): void {
    if (this._resizeFrameId !== null) {
      window.cancelAnimationFrame(this._resizeFrameId);
      this._resizeFrameId = null;
    }
  }

  /** Clears the pending scroll-adjust timer. */
  private _clearScrollAdjustTimer(): void {
    if (this._scrollAdjustTimerId !== null) {
      clearTimeout(this._scrollAdjustTimerId);
      this._scrollAdjustTimerId = null;
    }
  }

  /** Cancels deferred runtime work before bound markup is cleaned. */
  private _cancelScheduledRuntimeWork(): void {
    this._cancelScrollFrame();
    this._cancelResizeFrame();
    this._clearScrollAdjustTimer();
  }

  /**
   * Captures the active index before calculation replaces the current snapshot.
   * Returning both values prevents callers from reading the new index as if it were the previous one.
   */
  private _calculateSnapshotTransition(scrollY?: number): ISnapshotTransition {
    const previousActiveIndex = this.activeIndex;
    const snapshot = this._calculate(scrollY ?? getLastScrollPosition().y);
    return { previousActiveIndex, snapshot };
  }

  private _calculate(scrollY: number): ICalculationSnapshot {
    if (!this._layout) {
      throw new Error('Immerser layout is not set.');
    }

    const layerProgressArray = this._layerCalculationArray.map((layer) =>
      calculateLayerProgress(layer, scrollY, this._layout!.viewportHeight),
    );
    const transforms = this._layerCalculationArray.map((layer) =>
      calculateLayerTransform(layer, scrollY, this._layout!.rootHeight),
    );
    const activeIndex = calculateActiveIndex(
      this._layerCalculationArray,
      scrollY,
      this._layout.viewportHeight,
      this._options.pagerThreshold,
      this._snapshot.activeIndex,
    );

    this._snapshot = {
      activeIndex,
      layerProgressArray,
      transforms,
    };
    return this._snapshot;
  }

  /** Applies transforms based on scroll position and updates active layer state. */
  private _draw(snapshot: ICalculationSnapshot, previousActiveIndex: number): void {
    this._orderedLayerStateArray.forEach(({ maskNode, maskInnerNode }, layerIndex) => {
      if (!maskNode || !maskInnerNode) {
        return;
      }
      const transform = snapshot.transforms[layerIndex];
      maskNode.style.transform = `translateY(${transform.maskTranslateY}px)`;
      maskInnerNode.style.transform = `translateY(${transform.innerTranslateY}px)`;
    });

    if (!this._isBound || snapshot.activeIndex === previousActiveIndex) {
      return;
    }
    if (this._pagerLinkNodeArray.length > 0) {
      this._drawPagerLinks(snapshot.activeIndex);
    }
    if (this._options.hasToUpdateHash) {
      this._drawHash(snapshot.activeIndex);
    }
    this._emit('activeLayerChange', snapshot.activeIndex, this);
  }

  /** Adds or removes active pager classname according to current layer. */
  private _drawPagerLinks(layerIndex?: number): void {
    const layerId = layerIndex === undefined ? undefined : this._orderedLayerStateArray[layerIndex]?.id;
    this._pagerLinkNodeArray.forEach((pagerLinkNode) => {
      const hrefLayerId = (pagerLinkNode as HTMLAnchorElement).getAttribute('href')?.slice(1);
      if (hrefLayerId === layerId) {
        pagerLinkNode.classList.add(this._options.pagerLinkActiveClassname);
      } else {
        pagerLinkNode.classList.remove(this._options.pagerLinkActiveClassname);
      }
    });
  }

  /** Updates window hash to match active layer id. */
  private _drawHash(layerIndex: number): void {
    const layerState = this._orderedLayerStateArray[layerIndex];
    if (!layerState) {
      return;
    }
    const { id, layerNode } = layerState;
    layerNode.removeAttribute('id');
    window.location.hash = id;
    layerNode.setAttribute('id', id);
  }

  /** Syncs hover state across elements with matching synchroHover id. */
  private _drawSynchroHover(synchroHoverId?: string): void {
    this._synchroHoverNodeArray.forEach((synchroHoverNode) => {
      if (synchroHoverNode.dataset.immerserSynchroHover === synchroHoverId) {
        synchroHoverNode.classList.add('_hover');
      } else {
        synchroHoverNode.classList.remove('_hover');
      }
    });
  }

  /** Adjusts scroll to layer edges when near thresholds, improving alignment. */
  private _adjustScroll(): void {
    const { x, y } = getLastScrollPosition();
    const scrollTarget = this._calculateScrollTarget(y, this._options.scrollAdjustThreshold);
    if (scrollTarget !== null) {
      window.scrollTo(x, scrollTarget);
    }
  }

  private _calculateScrollTarget(scrollY: number, scrollAdjustThreshold: number): number | null {
    if (!this._layout) {
      throw new Error('Immerser layout is not set.');
    }

    const activeLayer = this._layerCalculationArray[this._snapshot.activeIndex];
    if (!activeLayer) {
      return null;
    }

    return calculateScrollTarget({
      activeLayer,
      scrollAdjustThreshold,
      scrollY,
      viewportHeight: this._layout.viewportHeight,
    });
  }

  /** RAF-throttled scroll handler that draws and optionally snaps scroll. */
  private _handleScroll(): void {
    if (this._isBound) {
      this._cancelScrollFrame();
      this._scrollFrameId = window.requestAnimationFrame(() => {
        const y = getLastScrollPosition().y;
        const { previousActiveIndex, snapshot } = this._calculateSnapshotTransition(y);
        this._emit('layersUpdate', [...snapshot.layerProgressArray], this);
        this._draw(snapshot, previousActiveIndex);
        if (this._options.scrollAdjustThreshold > 0) {
          this._clearScrollAdjustTimer();
          this._scrollAdjustTimerId = setTimeout(this._adjustScroll.bind(this), this._options.scrollAdjustDelay);
        }
      });
    }
  }

  /** RAF-throttled resize handler that recalculates sizes and redraws. */
  private _handleResize(): void {
    this._cancelResizeFrame();
    this._resizeFrameId = window.requestAnimationFrame(() => {
      this.render();
    });
  }

  /** Keeps updateOptions scoped to runtime fields even when called from plain JavaScript. */
  private _pickRuntimeOptions(userOptions: Partial<Options>): Partial<RuntimeOptions> {
    return RuntimeOptionNames.reduce<Partial<RuntimeOptions>>((result, optionName) => {
      if (optionName in userOptions) {
        result[optionName] = userOptions[optionName] as never;
      }
      return result;
    }, {});
  }

  /** Resolves markup ownership from the current DOM and prepares one runtime layer. */
  private prepareLayer(layerState: IDomLayerState): IDomLayerState {
    if (this._preparedLayerMarkupById.has(layerState.id)) {
      this.cleanupLayer(layerState.id);
    }

    this._ensureSourceSolids();
    const maskMarkup = this._resolveMaskMarkup(layerState.id);
    const clonedSolidArray = this._cloneSolids(layerState, maskMarkup.maskInnerNode);
    const solidNodeArray = this._collectSolidNodes(maskMarkup.maskInnerNode, clonedSolidArray);

    this._reportEmptyMarkup(maskMarkup.maskInnerNode);
    this._applyTechnicalStyles(maskMarkup, solidNodeArray);
    this._commitNodes(maskMarkup, clonedSolidArray);
    this._preparedLayerMarkupById.set(layerState.id, {
      ...maskMarkup,
      clonedSolidArray,
      solidNodeArray,
    });
    this._detachOriginalSolids();

    return {
      ...layerState,
      maskInnerNode: maskMarkup.maskInnerNode,
      maskNode: maskMarkup.maskNode,
    };
  }

  /** Removes only DOM effects owned for one prepared layer. */
  private cleanupLayer(layerId: string): void {
    const preparedLayerMarkup = this._preparedLayerMarkupById.get(layerId);
    if (!preparedLayerMarkup) {
      return;
    }

    const clonedSolidNodeSet = new Set(preparedLayerMarkup.clonedSolidArray.map(({ node }) => node));
    preparedLayerMarkup.clonedSolidArray.forEach(({ node }) => node.remove());
    preparedLayerMarkup.solidNodeArray
      .filter((node) => !clonedSolidNodeSet.has(node))
      .forEach((node) => node.removeAttribute('style'));
    if (preparedLayerMarkup.createdMask) {
      preparedLayerMarkup.maskNode.remove();
    } else {
      preparedLayerMarkup.maskNode.removeAttribute('style');
      preparedLayerMarkup.maskInnerNode.removeAttribute('style');
    }
    this._preparedLayerMarkupById.delete(layerId);
    if (this._preparedLayerMarkupById.size === 0) {
      (this._rootNode as HTMLElement).removeAttribute('style');
      this._restoreOriginalSolids();
      this._originalSolidNodeArray = [];
    }
  }

  /** Removes every controller-owned layer and clears global DOM effects. */
  private cleanup(): void {
    Array.from(this._preparedLayerMarkupById.keys()).forEach((layerId) => this.cleanupLayer(layerId));
  }

  /** Keeps aria hidden on generated duplicate masks only. */
  private syncCreatedMasksAria(orderedLayerIdArray: string[]): void {
    const createdLayerIdArray = orderedLayerIdArray.filter(
      (layerId) => this._preparedLayerMarkupById.get(layerId)?.createdMask,
    );
    createdLayerIdArray.forEach((layerId, layerIndex) => {
      const preparedLayerMarkup = this._preparedLayerMarkupById.get(layerId);
      if (!preparedLayerMarkup) {
        return;
      }
      if (layerIndex === 0) {
        preparedLayerMarkup.maskNode.removeAttribute('aria-hidden');
      } else {
        preparedLayerMarkup.maskNode.setAttribute('aria-hidden', 'true');
      }
    });
  }

  /** Finds source solids once and reuses detached originals for dynamic layer preparation. */
  private _ensureSourceSolids(): void {
    if (this._originalSolidNodeArray.length > 0) {
      return;
    }
    const maskNodeArray = queryElementArray({ selector: this._selectors.mask, parent: this._rootNode });
    this._originalSolidNodeArray = queryElementArray({
      selector: this._selectors.solid,
      parent: this._rootNode,
    }).filter((solidNode) => !maskNodeArray.some((maskNode) => maskNode.contains(solidNode)));
  }

  /** Uses an existing mask for layer id or creates a detached mask pair. */
  private _resolveMaskMarkup(layerId: string): IMaskMarkup {
    const existingMaskNodeArray = queryElementArray({ selector: this._selectors.mask, parent: this._rootNode }).filter(
      (maskNode) => maskNode.dataset.immerserLayerId === layerId,
    );
    if (existingMaskNodeArray.length > 1) {
      const message = `existing markup has duplicate mask layer id "${layerId}".`;
      this._report({ message, docsHash: '#prepare-your-markup' });
      throw new Error(message);
    }
    const existingMaskNode = existingMaskNodeArray[0];
    if (existingMaskNode) {
      return this._connectMaskMarkup(existingMaskNode);
    }
    return this._createMaskMarkup(layerId);
  }

  /** Creates one detached mask and its required inner node. */
  private _createMaskMarkup(layerId: string): IMaskMarkup {
    const maskNode = document.createElement('div');
    const maskInnerNode = document.createElement('div');
    maskNode.dataset.immerserMask = '';
    maskNode.dataset.immerserLayerId = layerId;
    maskInnerNode.dataset.immerserMaskInner = '';
    maskNode.appendChild(maskInnerNode);
    return { createdMask: true, maskInnerNode, maskNode };
  }

  /** Validates and connects the inner node belonging to an existing mask. */
  private _connectMaskMarkup(maskNode: HTMLElement): IMaskMarkup {
    const maskInnerNode = maskNode.querySelector<HTMLElement>(this._selectors.maskInner);
    if (!maskInnerNode) {
      const layerId = maskNode.dataset.immerserLayerId;
      const message = `existing markup mask-inner not found for layer id "${layerId}".`;
      this._report({ message, docsHash: '#prepare-your-markup' });
      throw new Error(message);
    }
    return { createdMask: false, maskInnerNode, maskNode };
  }

  /** Builds configured clones for one layer. */
  private _cloneSolids(layerState: IDomLayerState, maskInnerNode: HTMLElement): IClonedSolid[] {
    return this._originalSolidNodeArray.map((originalSolidNode) => {
      const clonedSolidNode = originalSolidNode.cloneNode(true) as HTMLElement;
      const solidId = clonedSolidNode.dataset.immerserSolid;
      const classname = solidId ? layerState.solidClassnames?.[solidId] : undefined;

      if (classname) {
        clonedSolidNode.classList.add(classname);
      }

      return {
        maskInnerNode,
        node: clonedSolidNode,
      };
    });
  }

  /** Collects existing and cloned solids that require interactive technical styles. */
  private _collectSolidNodes(maskInnerNode: HTMLElement, clonedSolidArray: IClonedSolid[]): HTMLElement[] {
    const existingSolidNodeArray = queryElementArray({ selector: this._selectors.solid, parent: maskInnerNode });
    return [...existingSolidNodeArray, ...clonedSolidArray.map(({ node }) => node)];
  }

  /** Warns when neither source solids nor existing mask content can produce a visual result. */
  private _reportEmptyMarkup(maskInnerNode: HTMLElement): void {
    if (this._originalSolidNodeArray.length === 0 && maskInnerNode.children.length === 0) {
      this._report({
        message: 'immerser will do nothing without source solids or existing mask content.',
        docsHash: '#prepare-your-markup',
        isWarning: true,
      });
    }
  }

  /** Replaces inline styles on controller-managed runtime nodes with technical styles. */
  private _applyTechnicalStyles(maskMarkup: IMaskMarkup, solidNodeArray: HTMLElement[]): void {
    this._setTechnicalStyles(this._rootNode as HTMLElement, NotInteractiveStyles);
    this._setTechnicalStyles(maskMarkup.maskNode, { ...CroppedFullAbsoluteStyles, transform: '' });
    this._setTechnicalStyles(maskMarkup.maskInnerNode, { ...CroppedFullAbsoluteStyles, transform: '' });
    solidNodeArray.forEach((node) => {
      this._setTechnicalStyles(node, InteractiveStyles);
    });
  }

  /** Drops client inline styles before assigning the complete technical style set. */
  private _setTechnicalStyles(node: HTMLElement, styles: Record<string, string>): void {
    node.removeAttribute('style');
    assignInlineStyles(node, styles);
  }

  /** Inserts staged clones and appends controller-created mask to the live root. */
  private _commitNodes(maskMarkup: IMaskMarkup, clonedSolidArray: IClonedSolid[]): void {
    clonedSolidArray.forEach(({ maskInnerNode, node }) => {
      maskInnerNode.appendChild(node);
    });
    if (maskMarkup.createdMask) {
      (this._rootNode as HTMLElement).appendChild(maskMarkup.maskNode);
    }
  }

  /** Detaches source solids after every clone and mask has been committed successfully. */
  private _detachOriginalSolids(): void {
    this._originalSolidNodeArray.forEach((solidNode) => solidNode.remove());
  }

  /** Returns detached source solids to the root in their original relative order. */
  private _restoreOriginalSolids(): void {
    this._originalSolidNodeArray.forEach((solidNode) => (this._rootNode as HTMLElement).appendChild(solidNode));
  }

  private _resetActiveIndex(): void {
    this._snapshot = {
      ...this._snapshot,
      activeIndex: -1,
    };
  }

  private _reset(): void {
    this._layerCalculationArray = [];
    this._layout = null;
    this._snapshot = {
      activeIndex: -1,
      layerProgressArray: [],
      transforms: [],
    };
  }

  /** Discovers DOM state, validates configuration and starts responsive runtime handling. */
  public mount(selectorRoot: ParentNode = document): void {
    if (this._isMounted) {
      return;
    }
    this._setDomNodes(selectorRoot);
    this._validateMarkup();
    this._validateLayerIds();
    this._readClassnamesFromMarkup();
    this._validateSolidClassnamesConfig();
    this._initLayerStateMap();
    this._isMounted = true;
    this._toggleBindOnResizeObserver();
    this._setSizes();
    this._addScrollAndResizeListeners();
  }

  /**
   * Enables runtime behavior: prepares markup, attaches hover runtime and triggers first draw; also emits bind event.
   * Intended to be idempotent for toggling immerser on when viewport width allows.
   */
  public enable(): void {
    if (!this.isMounted || this._isBound) {
      return;
    }
    this._prepareMarkup();
    this._initPagerLinks();
    this._initHoverSynchro();
    this._attachCallbacks();
    this._isBound = true;
    const { previousActiveIndex, snapshot } = this._calculateSnapshotTransition();
    this._draw(snapshot, previousActiveIndex);
    this._emit('bind', this);
  }

  /**
   * Disables runtime behavior: restores DOM, resets active layer and emits unbind event.
   * Safe to call multiple times; no-op when already disabled.
   */
  public disable(): void {
    if (!this._isBound) {
      return;
    }
    this._cancelScheduledRuntimeWork();
    this._detachCallbacks();
    this._removeSyncroHoverListeners();
    this._clearPagerLinks();
    this._cleanupMarkup();
    this._isBound = false;
    this._emit('unbind', this);
    this._resetActiveIndex();
  }

  /** Updates runtime options and applies minimal side effects without remounting the instance. */
  public updateOptions(userOptions: Partial<RuntimeOptions>): void {
    const previousOptions = this._options;
    const runtimeOptions = this._pickRuntimeOptions(userOptions as Partial<Options>);
    this._userOptions = { ...this._userOptions, ...runtimeOptions };
    const options = this._mergeOptions(this._userOptions);
    this._options = options;
    this.debug = options.debug;

    if (
      previousOptions.scrollAdjustDelay !== options.scrollAdjustDelay ||
      previousOptions.scrollAdjustThreshold !== options.scrollAdjustThreshold
    ) {
      this._clearScrollAdjustTimer();
    }

    if (!this._isMounted) {
      return;
    }

    if (previousOptions.isScrollHandled !== options.isScrollHandled) {
      options.isScrollHandled ? this._addScrollListener() : this._removeScrollListener();
    }
    if (previousOptions.fromViewportWidth !== options.fromViewportWidth) {
      this._setSizes();
    } else if (previousOptions.pagerThreshold !== options.pagerThreshold) {
      this.render();
    }
  }

  /**
   * Fully destroys immerser: disables runtime, removes mount-level listeners, runs destroy event and clears references.
   * Use when component is permanently removed.
   */
  public destroy(): void {
    this.disable();
    this._unsubscribeToggleBindOnResize?.();
    this._removeScrollAndResizeListeners();
    this._emit('destroy', this);
    this._resetInternalState();
    EventNames.forEach((eventName) => this._handlers[eventName].clear());
  }

  /**
   * Manually recomputes sizes and redraws masks; call after DOM mutations that change layout.
   * Exposed for dynamic content updates without reinitializing immerser.
   *
   * No throttling or performance optimization is applied here. The client is responsible for invocation frequency.
   */
  public render(): void {
    if (!this.isMounted) {
      return;
    }
    this._setSizes();
    const { previousActiveIndex, snapshot } = this._calculateSnapshotTransition();
    this._draw(snapshot, previousActiveIndex);
  }

  /**
   * Syncs immerser with an externally controlled scroll position.
   * `isScrollHandled=false` option flag is required to call this method.
   * Call when using a custom scroll handler.
   *
   * No throttling or performance optimization is applied here. The client is responsible for invocation frequency.
   */
  public syncScroll(): void {
    if (!this.isMounted) {
      return;
    }
    if (this._options.isScrollHandled) {
      this._report({
        message: 'syncScroll requires the isScrollHandled flag set to false. Call ignored.',
        isWarning: true,
        docsHash: '#external-scroll-engine',
      });
      return;
    }
    const { previousActiveIndex, snapshot } = this._calculateSnapshotTransition();
    this._draw(snapshot, previousActiveIndex);
  }

  /** Adds one layer and prepares its runtime markup when immerser is enabled. */
  public addLayer(
    id: string,
    layerNode: HTMLElement,
    order: number,
    solidClassnames: SolidClassnames | null = null,
  ): void {
    if (!this.isMounted) {
      return;
    }
    const layerState = this._addLayerState(id, layerNode, order, solidClassnames);
    if (this._isBound) {
      this._setLayerState(this.prepareLayer(layerState));
      this._syncCreatedMasksAria();
      this._initPagerLinks();
      this.render();
      return;
    }
    this._setSizes();
  }

  /** Removes one layer and its owned runtime markup. */
  public removeLayer(id: string): void {
    if (!this.isMounted) {
      return;
    }
    if (!this._layerStateById.has(id)) {
      return;
    }
    if (this._isBound) {
      this.cleanupLayer(id);
    }
    this._layerStateById.delete(id);
    this._syncCreatedMasksAria();
    this._initPagerLinks();
    this.render();
  }

  /** Register persistent event handler. */
  public on<K extends EventName>(eventName: K, handler: HandlerByEventName[K]): void {
    this._handlers[eventName].add(handler);
  }

  /** Register event handler that will be removed after first call. */
  public once<K extends EventName>(eventName: K, handler: HandlerByEventName[K]): void {
    this._handlers[eventName].add(
      wrapOnceHandler(handler, (...args: HandlerArgs<K>) => {
        this.off(eventName, handler);
        handler.apply(undefined, args);
      }),
    );
  }

  /** Removes handler(s) for provided event. */
  public off<K extends EventName>(eventName: K, handler: HandlerByEventName[K]): void {
    const handlerSet = this._handlers[eventName];

    handlerSet.forEach((storedHandler) => {
      const original = getOriginalHandler(storedHandler);
      if (storedHandler === handler || original === handler) {
        handlerSet.delete(storedHandler);
      }
    });
  }

  /** Current active layer index derived from scroll position. */
  public get activeIndex(): number {
    return this._snapshot.activeIndex;
  }

  /** Indicates whether immerser runtime is enabled (markup cloned and listeners attached). */
  public get isEnabled(): boolean {
    return this._isBound;
  }

  /** Indicates whether DOM discovery and mount-level listeners are active. */
  public get isMounted(): boolean {
    return this._isMounted;
  }

  /** The root DOM node immerser is attached to. */
  public get rootNode(): HTMLElement | null {
    return this._rootNode;
  }

  /** Progress of each layer from 0 (off-screen) to 1 (fully visible). */
  public get layerProgressArray(): readonly number[] {
    return this._snapshot.layerProgressArray;
  }
}

// for typedef generation needs
export type {
  ActiveLayerChangeHandler,
  BaseHandler,
  EventHandlers,
  EventName,
  HandlerByEventName,
  LayersUpdateHandler,
  Options,
  RuntimeOptions,
  SolidClassnames,
  SolidClassnamesByLayerId,
};
export { EventNames };
