import type { SolidClassnames } from '../types';

type Params = {
  existingLayerIdArray: readonly string[];
  existingLayerOrderArray: readonly number[];
  id: string;
  layerNode: HTMLElement;
  order: number;
  solidClassnames: SolidClassnames | null;
};

export default function validateLayerStateInput({
  existingLayerIdArray,
  existingLayerOrderArray,
  id,
  layerNode,
  order,
  solidClassnames,
}: Params): string | null {
  if (!id) {
    return 'layer id must be a non-empty string.';
  }
  if (!(layerNode instanceof HTMLElement)) {
    return `layer node for layer "${id}" must be an HTMLElement.`;
  }
  if (!Number.isInteger(order)) {
    return `layer order for layer "${id}" must be an integer.`;
  }
  if (existingLayerIdArray.includes(id)) {
    return `duplicate layer id "${id}".`;
  }
  if (existingLayerOrderArray.includes(order)) {
    return `duplicate layer order "${order}".`;
  }
  if (solidClassnames === null) {
    return null;
  }
  if (!solidClassnames || typeof solidClassnames !== 'object' || Array.isArray(solidClassnames)) {
    return `solid classnames for layer "${id}" must be an object.`;
  }
  if (Object.values(solidClassnames).some((classname) => typeof classname !== 'string')) {
    return `solid classnames for layer "${id}" must map solid ids to classname strings.`;
  }

  return null;
}
